(function(w){"use strict";const ID="power-root";function compute(x){const value=Number(x.value),mode=x.mode||"square";if(!Number.isFinite(value))return{error:"숫자를 올바르게 입력해 주세요."};let result;if(mode==="square")result=value*value;else if(mode==="sqrt"){if(value<0)return{error:"실수 범위에서 음수의 제곱근은 계산할 수 없습니다."};result=Math.sqrt(value)}else return{error:"계산 유형을 확인해 주세요."};if(!Number.isFinite(result))return{error:"계산 결과가 너무 큽니다."};return{value:result,label:mode==="square"?"제곱":"제곱근"}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label for="hm-power-root-mode">계산 유형</label><select id="hm-power-root-mode" class="hm-calc-select"><option value="square">제곱 (x²)</option><option value="sqrt">제곱근 (√x)</option></select></div><div class="hm-calc-field"><label for="hm-power-root-value">값</label><input id="hm-power-root-value" class="hm-calc-input" inputmode="decimal" placeholder="예: 144"></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const mode=root.querySelector("select"),v=root.querySelector("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({value:v.value,mode:mode.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard(r.label,api.formatNumber(r.value,12)));});reset.addEventListener("click",()=>{v.value="";mode.value="square";api.setMessage(msg,"");api.clearResult(res);v.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
